def article_url(slug, lang):
    base = GUIDES_PATH.get(lang, '/ratgeber')
    return base + '/' + slug


def ordered_slugs():
    return [s for s, _ in sorted(ARTICLES.items(), key=lambda kv: kv[1]['order'])]
